const src = $input.first().json;
const body = src.body || src;
const headers = src.headers || {};

// Extract JWT token from Authorization header or body
let token = '';
const authHeader = headers['authorization'] || headers['Authorization'] || '';
if (authHeader.startsWith('Bearer ')) {
  token = authHeader.slice(7).trim();
} else if (body.token) {
  token = (body.token || '').toString().trim();
}

if (!token) {
  return [{ json: { __authError: true } }];
}

let decoded;
try {
  const jwt = require('jsonwebtoken');
  decoded = jwt.verify(token, process.env.JWT_SECRET);
} catch (e) {
  return [{ json: { __authError: true } }];
}

const supplier_id = decoded.sub;
const body_supplier_id = (body.supplier_id || '').toString();

if (body_supplier_id && String(supplier_id) !== String(body_supplier_id)) {
  return [{ json: { __authError: true } }];
}

const method = (body.method || 'GET').toString().toUpperCase();
const status_filter = (body.status_filter || '').toString().trim();
const po = body.po || {};
const patch = body.patch || {};

return [{ json: { method, supplier_id, status_filter, po, patch, verified: true } }];

const src = $input.first().json;
const po = src.po || {};
const supplier_id = src.supplier_id;

// Validate required fields
if (!po.supplier_id && !supplier_id) throw new Error('supplier_id requerido');
if (!po.quote_id) throw new Error('quote_id requerido');
if (!Array.isArray(po.items) || po.items.length === 0) throw new Error('items[] requerido');
if (po.subtotal_equipment == null) throw new Error('subtotal_equipment requerido');
if (po.installation_total == null) throw new Error('installation_total requerido');

const eff_supplier_id = po.supplier_id || supplier_id;
const platform_fee_pct = Number(po.platform_fee_pct || 10);
const subtotal = Number(po.subtotal_equipment);
const installation = Number(po.installation_total);

// Calculate financials
const platform_fee_cop = Math.round(subtotal * platform_fee_pct / 100);
const supplier_net_cop = subtotal - platform_fee_cop;
const tech_fee_pct = Number(po.tech_fee_pct || 80);
const tech_earnings_cop = Math.round(installation * tech_fee_pct / 100);
const sh_install_fee_cop = installation - tech_earnings_cop;

// Generate PO number: PO-YYYYMMDD-XXXX
const now = new Date();
const datePart = now.toISOString().slice(0,10).replace(/-/g,'');
const randPart = Math.floor(1000 + Math.random() * 9000);
const po_number = `PO-${datePart}-${randPart}`;

return [{ json: {
  eff_supplier_id,
  quote_id: po.quote_id,
  technician_id: po.technician_id || null,
  po_number,
  subtotal_equipment: subtotal,
  platform_fee_pct,
  platform_fee_cop,
  supplier_net_cop,
  installation_total: installation,
  tech_fee_pct,
  tech_earnings_cop,
  sh_install_fee_cop,
  tracking_code: po.tracking_code || null,
  notes: po.notes || null,
  items: po.items
} }];

const poRow = $input.first().json;
const calc = $('Code: Calc PO').first().json;
const po_id = poRow.id;
const po_number = poRow.po_number;
const items = calc.items || [];

// Build bulk INSERT for po_items
if (!items.length) return [{ json: { po_id, po_number, items_inserted: 0 } }];

const valuePlaceholders = [];
const params = [];
let p = 1;
for (const item of items) {
  const line_total = Math.round(Number(item.qty || 1) * Number(item.unit_price_cop || 0));
  valuePlaceholders.push(`($${p++}::uuid, $${p++}::uuid, $${p++}, $${p++}, $${p++}, $${p++}, $${p++}, $${p++})`);
  params.push(po_id, item.stock_id || null, item.equipment_type || null, item.brand || null, item.model || null, Number(item.qty || 1), Number(item.unit_price_cop || 0), line_total);
}

// Store for next node
return [{ json: { po_id, po_number, insert_sql: `INSERT INTO po_items (po_id, stock_id, equipment_type, brand, model, qty, unit_price_cop, line_total_cop) VALUES ${valuePlaceholders.join(', ')}`, params, items_count: items.length, calc } }];

const prev = $('Code: Prep Items').first().json;
const po_id = prev.po_id;
const calc = prev.calc;

// Insert 2 commission rows: platform_equipment + tech_labor
const commissions = [
  {
    po_id,
    commission_type: 'platform_equipment',
    beneficiary: 'ALEBAS SolarHub',
    tech_id: null,
    supplier_id: calc.eff_supplier_id,
    amount_cop: calc.platform_fee_cop,
    pct: calc.platform_fee_pct,
    status: 'pendiente'
  },
  {
    po_id,
    commission_type: 'tech_labor',
    beneficiary: 'Instalador',
    tech_id: calc.technician_id || null,
    supplier_id: calc.eff_supplier_id,
    amount_cop: calc.tech_earnings_cop,
    pct: calc.tech_fee_pct,
    status: 'pendiente'
  }
];

const valuePlaceholders = commissions.map((_, i) => {
  const b = i * 8 + 1;
  return `($${b}::uuid, $${b+1}, $${b+2}, $${b+3}::int, $${b+4}::int, $${b+5}, $${b+6}, $${b+7})`;
});

const params = commissions.flatMap(c => [
  c.po_id,
  c.commission_type,
  c.beneficiary,
  c.tech_id,
  c.supplier_id,
  c.amount_cop,
  c.pct,
  c.status
]);

return [{ json: {
  insert_sql: `INSERT INTO commissions (po_id, commission_type, beneficiary, tech_id, supplier_id, amount_cop, pct, status) VALUES ${valuePlaceholders.join(', ')}`,
  params,
  po_id,
  po_number: prev.po_number
} }];

const row = $input.first().json;
if (!row || !row.id) {
  return [{ json: { ok: false, error: 'Pedido no encontrado o sin permiso' } }];
}
return [{ json: { ok: true, status: row.status, po_number: row.po_number, po_id: row.id } }];
